const chunks = [];
process.stdin.on('data', d => chunks.push(d));
process.stdin.on('end', () => {
  const raw = chunks.join('').replace(/\x1b\[[0-9;]*m/g, '');
  const start = raw.indexOf('[');
  const installs = JSON.parse(raw.slice(start));

  const today = new Date('2026-04-15T00:00:00Z');
  const warnDate = new Date('2026-05-15T00:00:00Z');
  const critical = [];
  const warnings = [];
  const okCerts = [];
  const noSslProd = [];

  for (const inst of installs) {
    const name = inst.name || 'UNKNOWN';
    const accountId = (inst.account || {}).id || 'UNKNOWN';
    const env = inst.environment || 'UNKNOWN';
    const domain = inst.primaryDomain || 'N/A';
    const ssl = inst.ssl;

    if (!ssl) {
      if (env === 'production') noSslProd.push({name, accountId, domain, env});
      continue;
    }
    const certs = ssl.certificates || [];
    if (!certs.length) {
      if (env === 'production') noSslProd.push({name, accountId, domain, env, note: 'ssl obj but no certs'});
      continue;
    }
    for (const cert of certs) {
      const cn = cert.common_name || 'N/A';
      const cid = cert.id;
      const cstat = cert.status || 'UNKNOWN';
      const csrc = cert.cert_source || 'N/A';
      const expRaw = cert.expires_time;
      if (!expRaw) {
        warnings.push({name, accountId, domain, cn, cid, cstat, csrc, exp: 'N/A', days: null, issue: 'No expiry date'});
        continue;
      }
      const expDt = new Date(expRaw);
      const days = Math.floor((expDt - today) / 86400000);
      if (expDt < today) {
        critical.push({name, accountId, domain, cn, cid, cstat, csrc, exp: expDt.toISOString().slice(0,10), days, issue: 'EXPIRED ' + Math.abs(days) + ' days ago'});
      } else if (expDt < warnDate) {
        warnings.push({name, accountId, domain, cn, cid, cstat, csrc, exp: expDt.toISOString().slice(0,10), days, issue: 'Expires in ' + days + ' days'});
      } else {
        okCerts.push({name, domain, cn, exp: expDt.toISOString().slice(0,10), days, cstat});
      }
    }
  }

  const SEP = '='.repeat(80);
  console.log(SEP);
  console.log('SSL CERTIFICATE HEALTH REPORT');
  console.log('Generated: 2026-04-15  |  Fleet size: ' + installs.length + ' installs');
  console.log(SEP);
  console.log('');
  console.log('SUMMARY');
  console.log('  Total installs:          ' + installs.length);
  console.log('  Certs with issues:       ' + (critical.length + warnings.length));
  console.log('  Healthy certs:           ' + okCerts.length);
  console.log('  Production with no SSL:  ' + noSslProd.length);
  console.log('  CRITICAL (expired):      ' + critical.length);
  console.log('  WARNING (expires <30d):  ' + warnings.length);

  if (critical.length) {
    console.log('');
    console.log(SEP);
    console.log('!! CRITICAL -- EXPIRED CERTIFICATES');
    console.log(SEP);
    for (const i of critical) {
      console.log('');
      console.log('  Install:     ' + i.name);
      console.log('  Account:     ' + i.accountId);
      console.log('  Domain:      ' + i.domain);
      console.log('  Common Name: ' + i.cn);
      console.log('  Cert ID:     ' + i.cid);
      console.log('  Source:      ' + i.csrc);
      console.log('  Cert Status: ' + i.cstat);
      console.log('  Expired:     ' + i.exp + '  --> ' + i.issue);
    }
  }

  if (warnings.length) {
    console.log('');
    console.log(SEP);
    console.log('!! WARNING -- CERTIFICATES EXPIRING WITHIN 30 DAYS');
    console.log(SEP);
    const sorted = warnings.slice().sort((a,b) => (a.days||999) - (b.days||999));
    for (const i of sorted) {
      console.log('');
      console.log('  Install:     ' + i.name);
      console.log('  Account:     ' + i.accountId);
      console.log('  Domain:      ' + i.domain);
      console.log('  Common Name: ' + i.cn);
      console.log('  Cert ID:     ' + i.cid);
      console.log('  Source:      ' + i.csrc);
      console.log('  Cert Status: ' + i.cstat);
      console.log('  Expires:     ' + i.exp + '  --> ' + i.issue);
    }
  }

  if (noSslProd.length) {
    console.log('');
    console.log(SEP);
    console.log('INFO -- PRODUCTION INSTALLS WITH NO SSL CONFIGURED');
    console.log(SEP);
    for (const s of noSslProd) {
      console.log('');
      console.log('  Install:     ' + s.name);
      console.log('  Account:     ' + s.accountId);
      console.log('  Domain:      ' + s.domain);
      console.log('  Environment: ' + s.env);
      if (s.note) console.log('  Note:        ' + s.note);
    }
  }

  if (okCerts.length) {
    console.log('');
    console.log(SEP);
    console.log('HEALTHY CERTIFICATES (no action needed)');
    console.log(SEP);
    okCerts.sort((a,b) => a.days - b.days);
    for (const c of okCerts) {
      const nm = c.name.padEnd(30);
      const cn = c.cn.padEnd(42);
      console.log('  ' + nm + '  ' + cn + '  exp ' + c.exp + '  (' + String(c.days).padStart(4) + 'd)  [' + c.cstat + ']');
    }
  }

  console.log('');
  console.log(SEP);
  console.log('END OF REPORT');
  console.log(SEP);
});
"

